script:
frappe.ui.form.on('Nakoda Ledger Day', {
    refresh: function(frm) {
        const show_report = (html) => {
            let d = new frappe.ui.Dialog({
                title: __("Import Analysis Report"),
                size: "extra-large",
                fields: [
                    { fieldname: "report_html", fieldtype: "HTML", options: html }
                ]
            });
            d.$wrapper.find(".modal-dialog").css("max-width", "92%");
            d.show();
        };

        if (frm.doc.import_log) {
            frm.add_custom_button(__("View Import Report"), function() {
                show_report(frm.doc.import_log);
            });
        }
        // Updated color formatters for Hindi transaction types
        try {
            if (frm.fields_dict.ledger_rows && frm.fields_dict.ledger_rows.grid) {
                frm.fields_dict.ledger_rows.grid.formatters['transaction_type'] = function(value, df, options, doc) {
                    if (value === 'जमा') {
                        return `<strong style="color: white; background-color: var(--success-color, #28a745); padding: 2px 8px; border-radius: 12px; font-size: 11px;">${value}</strong>`;
                    } else if (value === 'उधारी') {
                        return `<strong style="color: white; background-color: var(--danger-color, #dc3545); padding: 2px 8px; border-radius: 12px; font-size: 11px;">${value}</strong>`;
                    }
                    return value;
                };

                frm.fields_dict.ledger_rows.grid.formatters['status'] = function(value, df, options, doc) {
                    if (value === 'Pending') {
                        return `<span style="color: #d39e00; font-weight: bold;">⏳ ${value}</span>`;
                    } else if (value === 'Posted') {
                        return `<span style="color: #28a745; font-weight: bold;">✅ ${value}</span>`;
                    } else if (value === 'Skipped' || value === 'Failed' || value === 'Duplicate') {
                        return `<span style="color: #dc3545; font-weight: bold;">❌ ${value}</span>`;
                    }
                    return value;
                };
            }
        } catch(e) {
            console.log("Grid formatter attach skipped", e);
        }

        let is_posted = frm.doc.rows_processed > 0;
        let pending_rows = frm.doc.ledger_rows ? frm.doc.ledger_rows.filter(r => r.status === 'Pending').length : 0;

        if (frm.doc.excel_file && !is_posted) {
            frm.add_custom_button(__('Parse Excel Ledger'), function() {
                frappe.call({
                    method: 'nakoda_automation.ledger_sync.api.parse_excel_ledger',
                    args: {
                        file_url: frm.doc.excel_file,
                        dashboard_id: frm.doc.name
                    },
                    freeze: true,
                    freeze_message: __('Parsing Excel Grid & Resolving Customers...'),
                    callback: function(r) {
                        if (r.message && r.message.status === 'success') {
                            show_report(r.message.message);
                            frm.reload_doc();
                        } else if (r.message && r.message.status === 'error') {
                            frappe.msgprint({
                                title: __('Error'),
                                indicator: 'red',
                                message: r.message.message
                            });
                            frm.reload_doc();
                        }
                    }
                });
            }).removeClass('btn-default').addClass('btn-primary');
        }

        if (pending_rows > 0 && !is_posted) {
            frm.add_custom_button(__('Post Ledger Entries (' + pending_rows + ')'), function() {
                frappe.call({
                    method: 'nakoda_automation.ledger_sync.api.post_ledger_entries',
                    args: {
                        dashboard_id: frm.doc.name
                    },
                    freeze: true,
                    freeze_message: __('Committing financial entries...'),
                    callback: function(r) {
                        if (r.message && r.message.status === 'success') {
                            show_report(r.message.message);
                            frm.reload_doc();
                        } else if (r.message && r.message.status === 'error') {
                            frappe.msgprint({
                                title: __('Error'),
                                indicator: 'red',
                                message: r.message.message
                            });
                            frm.reload_doc();
                        }
                    }
                });
            }).removeClass('btn-default').addClass('btn-danger');
        }
    }
});
